-- =============================================================================
-- V3__seed_data.sql
-- Flyway V3 migration: Seed data for CardDemo Aurora PostgreSQL
--
-- Source fixtures:
--   app/data/ASCII/trantype.txt    ->  7 transaction_types
--   app/data/ASCII/trancatg.txt    -> 18 transaction_categories
--   app/jcl/DUSRSECJ.jcl  (inline) -> 10 user_security (BCrypt-hashed)
--   app/data/ASCII/discgrp.txt     -> 51 disclosure_groups
--   app/data/ASCII/acctdata.txt    -> 50 accounts
--   app/data/ASCII/carddata.txt    -> 50 cards
--   app/data/ASCII/custdata.txt    -> 50 customers
--   app/data/ASCII/cardxref.txt    -> 50 card_cross_references
--   app/data/ASCII/tcatbal.txt     -> 50 transaction_category_balances
--   app/data/ASCII/dailytran.txt   -> 300 daily_transactions
--
-- Transformation rules:
--   * COBOL fixed-width ASCII -> PostgreSQL INSERT statements
--   * PIC S9(n)V99 zoned decimal: last byte is sign overpunch (see AAP §0.7)
--     Positive overpunch: '{'=+0, 'A'=+1..'I'=+9
--     Negative overpunch: '}'=-0, 'J'=-1..'R'=-9
--   * PIC X(n) string fields trimmed of trailing spaces for VARCHAR columns
--   * Dates stored as VARCHAR(10) in YYYY-MM-DD format (matches V1 schema)
--   * Passwords hashed with BCrypt $2b$12$ (plaintext source: 'PASSWORD')
--
-- Per AAP §0.7.1: preserves all existing data exactly as-is; no transformation
-- of values beyond decoding COBOL overpunch and trimming padding.
--
-- Per AAP §0.5.1: INSERT order respects logical dependency order
-- (reference tables first, then entity tables, then relationship tables).
-- =============================================================================

-- ----------------------------------------------------------------
-- Phase 1: transaction_types (7 rows)
-- Source: app/data/ASCII/trantype.txt
-- Record layout: PIC X(02) type_code + PIC X(50) desc + 8-byte filler
-- ----------------------------------------------------------------

-- ----------------------------------------------------------------
-- Phase 2: transaction_categories (18 rows)
-- Source: app/data/ASCII/trancatg.txt
-- Record layout (CVTRA04Y.cpy): PIC X(02) type_code + PIC 9(04) cat_code
--                              + PIC X(50) desc + 4-byte filler
-- ----------------------------------------------------------------

-- ----------------------------------------------------------------
-- Phase 3: user_security (10 rows)
-- Source: app/jcl/DUSRSECJ.jcl (inline 80-byte SYSIN records)
-- Record layout (CSUSR01Y.cpy):
--   pos  1-8  SEC-USR-ID     PIC X(08)
--   pos  9-28 SEC-USR-FNAME  PIC X(20)
--   pos 29-48 SEC-USR-LNAME  PIC X(20)
--   pos 49-56 SEC-USR-PWD    PIC X(08)  -> BCrypt $2b$12$ hash
--   pos 57    SEC-USR-TYPE   PIC X(01)  -> 'A' admin | 'U' user
--   pos 58-80 FILLER         PIC X(23)
-- Passwords: source plaintext is 'PASSWORD' for all users;
-- stored as BCrypt hashes (cost factor 12) per AAP §0.5.1 security rules.
-- ----------------------------------------------------------------

-- ----------------------------------------------------------------
-- Phase 4: disclosure_groups (51 rows)
-- Source: app/data/ASCII/discgrp.txt
-- Record layout (CVTRA02Y.cpy):
--   pos  1-10 DIS-ACCT-GROUP-ID PIC X(10)
--   pos 11-12 DIS-TRAN-TYPE-CD  PIC X(02)
--   pos 13-16 DIS-TRAN-CAT-CD   PIC 9(04)
--   pos 17-22 DIS-INT-RATE      PIC S9(04)V99  (zoned decimal, last byte = overpunch)
--   pos 23-50 FILLER
-- Three blocks: A000000000 (17), DEFAULT (17), ZEROAPR (17).
-- ----------------------------------------------------------------

-- ----------------------------------------------------------------
-- Phase 5: accounts (50 rows)
-- Source: app/data/ASCII/acctdata.txt
-- Record layout (CVACT01Y.cpy, 300 bytes):
--   pos   1-11 ACCT-ID                PIC 9(11)
--   pos     12 ACCT-ACTIVE-STATUS     PIC X(01)
--   pos  13-24 ACCT-CURR-BAL          PIC S9(10)V99
--   pos  25-36 ACCT-CREDIT-LIMIT      PIC S9(10)V99
--   pos  37-48 ACCT-CASH-CREDIT-LIMIT PIC S9(10)V99
--   pos  49-58 ACCT-OPEN-DATE         PIC X(10)
--   pos  59-68 ACCT-EXPIRAION-DATE    PIC X(10)
--   pos  69-78 ACCT-REISSUE-DATE      PIC X(10)
--   pos  79-90 ACCT-CURR-CYC-CREDIT   PIC S9(10)V99
--   pos 91-102 ACCT-CURR-CYC-DEBIT    PIC S9(10)V99
--   pos 103-112 ACCT-GROUP-ID         PIC X(10)  (data layout swap)
--   pos 113-122 ACCT-ADDR-ZIP         PIC X(10)  (data layout swap)
--   pos 123-300 FILLER
-- Signed zoned-decimal fields use COBOL overpunch on the last byte.
-- ----------------------------------------------------------------

-- ----------------------------------------------------------------
-- Phase 6: cards (50 rows)
-- Source: app/data/ASCII/carddata.txt
-- Record layout (CVACT02Y.cpy, 150 bytes):
--   pos  1-16 CARD-NUM             PIC X(16)
--   pos 17-27 CARD-ACCT-ID         PIC 9(11)
--   pos 28-30 CARD-CVV-CD          PIC 9(03)
--   pos 31-80 CARD-EMBOSSED-NAME   PIC X(50)
--   pos 81-90 CARD-EXPIRATION-DATE PIC X(10)
--   pos    91 CARD-ACTIVE-STATUS   PIC X(01)
--   pos 92-150 FILLER
-- ----------------------------------------------------------------

-- ----------------------------------------------------------------
-- Phase 7: customers (50 rows)
-- Source: app/data/ASCII/custdata.txt
-- Record layout (CVCUS01Y.cpy, 500 bytes):
--   pos   1-9  CUST-ID                    PIC 9(09)
--   pos 10-34  CUST-FIRST-NAME            PIC X(25)
--   pos 35-59  CUST-MIDDLE-NAME           PIC X(25)
--   pos 60-84  CUST-LAST-NAME             PIC X(25)
--   pos 85-134 CUST-ADDR-LINE-1           PIC X(50)
--   pos 135-184 CUST-ADDR-LINE-2          PIC X(50)
--   pos 185-234 CUST-ADDR-LINE-3          PIC X(50)
--   pos 235-236 CUST-ADDR-STATE-CD        PIC X(02)
--   pos 237-239 CUST-ADDR-COUNTRY-CD      PIC X(03)
--   pos 240-249 CUST-ADDR-ZIP             PIC X(10)
--   pos 250-264 CUST-PHONE-NUM-1          PIC X(15)
--   pos 265-279 CUST-PHONE-NUM-2          PIC X(15)
--   pos 280-288 CUST-SSN                  PIC 9(09)
--   pos 289-308 CUST-GOVT-ISSUED-ID       PIC X(20)
--   pos 309-318 CUST-DOB-YYYY-MM-DD       PIC X(10)
--   pos 319-328 CUST-EFT-ACCOUNT-ID       PIC X(10)
--   pos     329 CUST-PRI-CARD-HOLDER-IND  PIC X(01)
--   pos 330-332 CUST-FICO-CREDIT-SCORE    PIC 9(03)
--   pos 333-500 FILLER
-- ----------------------------------------------------------------

-- ----------------------------------------------------------------
-- Phase 8: card_cross_references (50 rows)
-- Source: app/data/ASCII/cardxref.txt
-- Record layout (CVACT03Y.cpy, 36 bytes in fixture):
--   pos   1-16 XREF-CARD-NUM PIC X(16)
--   pos  17-25 XREF-CUST-ID  PIC 9(09)
--   pos  26-36 XREF-ACCT-ID  PIC 9(11)
-- ----------------------------------------------------------------

-- ----------------------------------------------------------------
-- Phase 9: transaction_category_balances (50 rows)
-- Source: app/data/ASCII/tcatbal.txt
-- Record layout (CVTRA01Y.cpy, 50 bytes):
--   pos   1-11 TRANCAT-ACCT-ID PIC 9(11)
--   pos  12-13 TRANCAT-TYPE-CD PIC X(02)
--   pos  14-17 TRANCAT-CD      PIC 9(04)
--   pos  18-28 TRAN-CAT-BAL    PIC S9(09)V99  (11 bytes zoned decimal)
--   pos  29-50 FILLER
-- ----------------------------------------------------------------

-- ----------------------------------------------------------------
-- Phase 10: daily_transactions (300 rows)
-- Source: app/data/ASCII/dailytran.txt
-- Record layout (CVTRA06Y.cpy, 350 bytes) — identical to TRAN-RECORD:
--   pos   1-16  DALYTRAN-ID            PIC X(16)
--   pos  17-18  DALYTRAN-TYPE-CD       PIC X(02)
--   pos  19-22  DALYTRAN-CAT-CD        PIC 9(04)
--   pos  23-32  DALYTRAN-SOURCE        PIC X(10)
--   pos  33-132 DALYTRAN-DESC          PIC X(100)
--   pos 133-143 DALYTRAN-AMT           PIC S9(09)V99  (11 bytes zoned decimal)
--   pos 144-152 DALYTRAN-MERCHANT-ID   PIC 9(09)
--   pos 153-202 DALYTRAN-MERCHANT-NAME PIC X(50)
--   pos 203-252 DALYTRAN-MERCHANT-CITY PIC X(50)
--   pos 253-262 DALYTRAN-MERCHANT-ZIP  PIC X(10)
--   pos 263-278 DALYTRAN-CARD-NUM      PIC X(16)
--   pos 279-304 DALYTRAN-ORIG-TS       PIC X(26)
--   pos 305-330 DALYTRAN-PROC-TS       PIC X(26)
--   pos 331-350 FILLER
-- Processing timestamp is blank on intake; populated by POSTTRAN (Stage 1).
-- ----------------------------------------------------------------

-- ==============================================================================
-- End of V3__seed_data.sql
